+using System.Text.RegularExpressions;
+
+namespace DocSummary.Services;
+
+public partial class DocumentSummarizer
+{
+    // Common English stop words excluded from scoring.
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a","an","the","and","or","but","is","are","was","were","be","been",
+        "being","have","has","had","do","does","did","will","would","shall",
+        "should","may","might","must","can","could","i","you","he","she","it",
+        "we","they","me","him","her","us","them","my","your","his","its","our",
+        "their","this","that","these","those","in","on","at","to","for","of",
+        "with","by","from","as","into","about","between","through","after",
+        "above","below","up","down","out","off","over","under","not","no","so",
+        "if","then","than","too","very","just","also","more","most","such",
+        "each","every","all","any","both","few","many","some","other","only"
+    };
+
+    [GeneratedRegex(@"(?<=[.!?])\s+")]
+    private static partial Regex SentenceSplitter();
+
+    [GeneratedRegex(@"[^\w\s]")]
+    private static partial Regex PunctuationStripper();
+
+    /// <summary>
+    /// Produces an extractive summary by scoring sentences on word frequency
+    /// and returning the top-ranked ones in their original order.
+    /// </summary>
+    public string Summarize(string text, int maxSentences)
+    {
+        if (string.IsNullOrWhiteSpace(text))
+            return string.Empty;
+
+        var sentences = SentenceSplitter()
+            .Split(text)
+            .Where(s => !string.IsNullOrWhiteSpace(s))
+            .ToList();
+
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = BuildWordFrequencies(sentences);
+        var scored = ScoreSentences(sentences, wordFrequencies);
+
+        var topIndices = scored
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .Select(s => s.Index)
+            .OrderBy(i => i);
+
+        return string.Join(" ", topIndices.Select(i => sentences[i]));
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in Tokenize(sentence))
+            {
+                if (!StopWords.Contains(word))
+                    freq[word] = freq.GetValueOrDefault(word) + 1;
+            }
+        }
+        return freq;
+    }
+
+    private static List<(int Index, double Score)> ScoreSentences(
+        List<string> sentences,
+        Dictionary<string, int> wordFrequencies)
+    {
+        var scored = new List<(int Index, double Score)>(sentences.Count);
+        for (int i = 0; i < sentences.Count; i++)
+        {
+            var words = Tokenize(sentences[i]);
+            double score = words.Where(w => !StopWords.Contains(w))
+                                .Sum(w => wordFrequencies.GetValueOrDefault(w));
+
+            // Normalize by word count to avoid bias toward long sentences.
+            if (words.Length > 0)
+                score /= words.Length;
+
+            scored.Add((i, score));
+        }
+        return scored;
+    }
+
+    private static string[] Tokenize(string sentence) =>
+        PunctuationStripper()
+            .Replace(sentence, "")
+            .Split(' ', StringSplitOptions.RemoveEmptyEntries);
+}
